def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        decay = 1.0
        for step in range(5):
            if ratio < 0.05:
                score += decay * ((0.05 - ratio) ** 3)
            elif ratio < 0.3:
                score += decay * ((0.3 - ratio) ** 2) * 0.8
            elif ratio < 0.7:
                score += decay * (np.sin(ratio * np.pi) + 0.5)
            else:
                score += decay * np.log1p(ratio) * 1.2
            decay *= 0.7
            if step % 2 == 0:
                ratio = ratio ** 1.5
            else:
                ratio = np.sqrt(ratio)
        if score < 0:
            score = 0
        if capacity % 2 == 0:
            score *= 1.1
        else:
            score *= 0.9
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority + 2
    if np.mean(priorities) > 10:
        priorities = priorities / np.max(priorities) * 5
    return priorities
